programs._raw:
{
  "name": "Caregiver Resource Centers (CRC)",
  "eligibility": {
    "age": null,
    "income_limits": "No income or asset limits specified; services provided at low or no cost to all eligible family caregivers.[3][4]",
    "asset_limits": "No asset limits or exclusions detailed in available information.[3]",
    "other_requirements": [
      "Must be a family caregiver (relative, partner, friend, etc.) providing care to an adult with cognitive impairment or chronic/debilitating health conditions such as dementia, Alzheimer’s, stroke, Parkinson’s, Huntington’s, multiple sclerosis, or traumatic brain injury.[3][4]",
      "Primary caregiver of the care recipient.[3]"
    ]
  },
  "benefits": {
    "type": "service",
    "value": "Core services include: Specialized information and referral; family consultation and care planning; respite care (financial assistance for in-home support, adult day care, short-term/weekend care, transportation); short-term counseling (individual, family, group); support groups (online/in-person); professional training workshops; legal and financial consultation (Powers of Attorney, advance directives, estate planning, conservatorships); education workshops on cognitive disorders, dementia, long-term care, stress management. No specific dollar amounts or hours per week stated; respite provides financial assistance but amounts not quantified.[4]",
    "varies_by": "region"
  },
  "application": {
    "methods": [
      "Contact the specific CRC serving your county by phone or website (11 regional centers cover all 58 counties; examples: Inland CRC (909) 514-1404 or (800) 675-6694, www.inlandcaregivers.org; Redwood CRC (707) 542-0282 or (800) 834-1636, www.redwoodcrc.org).[5]",
      "Call local provider for intake and eligibility process (e.g., LA County: 1-800-510-2020).[1]",
      "Online via CareNav™ for resource connection.[7]"
    ],
    "processing_time": "Not specified.",
    "waitlist": null,
    "forms": [],
    "documents": [
      "Verification of caregiver’s age and residency.",
      "Verification of care recipient’s age (if applicable, e.g., 60+) and condition.",
      "For older relative caregivers: proof of relationship and residency.[1]"
    ]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Services available in all 58 counties via 11 nonprofit CRCs; each center serves specific counties (e.g., Inland: Inyo, Mono, Riverside, San Bernardino; Redwood: Del Norte, Humboldt, Lake, Mendocino, Napa, Solano, Sonoma).[3][5][7]",
    "regional_variations": "Each CRC tailors services to its geographic area based on local needs; core services consistent but delivery varies by center.[3][4]",
    "offices_or_providers": [
      "Network of 11 nonprofit centers covering all counties (full list at caregivercalifornia.org or aging.ca.gov).[3][5][9]"
    ]
  },
  "official_source": "https://www.aging.ca.gov/Providers_and_Partners/Caregiver_Resource_Centers/Program_Narrative_and_Fact_Sheets/",
  "gotchas": [
    "Not a paid caregiver program; focuses on support services for unpaid family caregivers, not direct compensation (compare to IHSS for payment options).[2][6]",
    "Administered regionally by 11 different nonprofits, so contact the specific CRC for your county rather than a single statewide office.[3][5][7]",
    "No fixed dollar amounts or hours for benefits like respite; financial assistance varies and requires assessment.[4]",
    "Consent not always required for services, but verification documents needed for eligibility.[1]"
  ],
  "data_shape_notes": "Network of 11 regional nonprofit centers covering all counties with tailored services; no income/asset tests; core services statewide but customized locally; not for paid caregiving."
}
